"import json

path = "/Users/pravinsam/.gemini/antigravity-ide/brain/353b6a43-7fa1-4a16-b18d-9ef0cd6ad7d2/.system_generated/logs/transcript.jsonl"
with open(path, "r") as f:
    for line in f:
        data = json.loads(line)
        tcalls = data.get("tool_calls", [])
        if isinstance(tcalls, list):
            for tc in tcalls:
                args = tc.get("args", {})
                target = str(args.get("TargetFile", "")) or str(args.get("AbsolutePath", "")) or str(args.get("Target", ""))
                if "dining.html" in target:
                    print(f"Step {data.get('step_index')}: tool={tc.get('name')}, args={list(args.keys())}")
                    if tc.get("name") == "write_to_file":
                        print("Written file size:", len(args.get("CodeContent", "")))
                    elif tc.get("name") == "replace_file_content":
                        print("Replaced size:", len(args.get("ReplacementContent", "")))
"
